import java.util.*;

public class Solution {

    // Helper class for Dijkstra's algorithm
    static class Edge {
        int to;
        long weight;

        public Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    // Helper class for Priority Queue elements
    static class Node implements Comparable<Node> {
        int id;
        long distance;

        public Node(int id, long distance) {
            this.id = id;
            this.distance = distance;
        }

        @Override
        public int compareTo(Node other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    /**
     * Runs Dijkstra's algorithm from a source node on the given adjacency list.
     * @param n The number of nodes.
     * @param adj The adjacency list where adj[u] contains edges starting from u.
     * @param startNode The source node.
     * @return An array of minimum distances from startNode to all other nodes.
     */
    private static long[] dijkstra(int n, List<List<Edge>> adj, int startNode) {
        long[] dist = new long[n];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[startNode] = 0;

        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(startNode, 0));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            int u = current.id;
            long d = current.distance;

            if (d > dist[u]) {
                continue;
            }

            for (Edge edge : adj.get(u)) {
                int v = edge.to;
                long weight = edge.weight;

                if (dist[u] != Long.MAX_VALUE && dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new Node(v, dist[v]));
                }
            }
        }
        return dist;
    }

    public static long[] solve(long n_long, long[] prices, long[][] roads) {
        int n = (int) n_long;

        // 1. Build adjacency lists for empty travel and full travel
        List<List<Edge>> adjEmpty = new ArrayList<>(n);
        List<List<Edge>> adjFull = new ArrayList<>(n);

        for (int i = 0; i < n; i++) {
            adjEmpty.add(new ArrayList<>());
            adjFull.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];

            // Weights for empty travel (cost)
            long emptyWeight = cost;

            // Weights for full travel (cost * tax)
            // Since cost <= 10^9 and tax <= 100, cost * tax <= 10^11, which fits in long.
            long fullWeight = cost * tax;

            // Bidirectional edges
            // Empty Graph
            adjEmpty.get(u).add(new Edge(v, emptyWeight));
            adjEmpty.get(v).add(new Edge(u, emptyWeight));

            // Full Graph
            adjFull.get(u).add(new Edge(v, fullWeight));
            adjFull.get(v).add(new Edge(u, fullWeight));
        }

        // 2. Calculate APSP for both graphs
        // D_empty[i][j]: Shortest path from i to j without apple
        long[][] D_empty = new long[n][n];
        // D_full[i][j]: Shortest path from i to j carrying apple
        long[][] D_full = new long[n][n];

        // Run Dijkstra N times for empty graph
        for (int i = 0; i < n; i++) {
            long[] dists = dijkstra(n, adjEmpty, i);
            for (int j = 0; j < n; j++) {
                D_empty[i][j] = dists[j];
            }
        }

        // Run Dijkstra N times for full graph
        for (int i = 0; i < n; i++) {
            long[] dists = dijkstra(n, adjFull, i);
            for (int j = 0; j < n; j++) {
                D_full[i][j] = dists[j];
            }
        }

        // 3. Calculate the minimum cost for each shop i
        long[] ans = new long[n];

        for (int i = 0; i < n; i++) {
            // Option 1: Buy directly at i
            long minCost = prices[i];

            // Option 2: Travel i -> j -> i
            for (int j = 0; j < n; j++) {
                if (i == j) continue;

                // Cost = D_empty(i, j) + prices[j] + D_full(j, i)

                // Check if paths exist. If any required shortest path is infinity, skip this j.
                if (D_empty[i][j] == Long.MAX_VALUE || D_full[j][i] == Long.MAX_VALUE) {
                    continue;
                }

                // Calculate total cost for this route
                // D_empty[i][j] + prices[j] + D_full[j][i]
                long currentCost = D_empty[i][j] + prices[j] + D_full[j][i];

                minCost = Math.min(minCost, currentCost);
            }
            ans[i] = minCost;
        }

        return ans;
    }
}

