 * @param {number} n - Number of nodes.
 * @param {Array<Array<[number, number]>>} adj - Adjacency list: adj[u] = [[v1, weight1], [v2, weight2], ...]
 * @param {number} startNode - The source node.
 * @returns {Array<number>} An array of minimum distances from startNode to all other nodes.
 */
function dijkstra(n, adj, startNode) {
    // Use Infinity for unreachable nodes. Since costs can be large (up to 10^14), standard JS Number is safe enough.
    const dist = new Array(n).fill(Infinity);
    dist[startNode] = 0;

    const pq = new MinPriorityQueue();
    pq.enqueue(0, startNode); // [distance, node]

    while (!pq.isEmpty()) {
        const { priority: d, value: u } = pq.dequeue();

        if (d > dist[u]) {
            continue;
        }

        for (const [v, weight] of adj[u]) {
            const newDist = dist[u] + weight;
            if (newDist < dist[v]) {
                dist[v] = newDist;
                pq.enqueue(newDist, v);
            }
        }
    }
    return dist;
}


function solve(n, prices, roads) {
