        adjE[u].push([v, cost]);
        adjE[v].push([u, cost]);

        // Carrying state: cost * tax
        const carryingCost = cost * tax;
        adjC[u].push([v, carryingCost]);
        adjC[v].push([u, carryingCost]);
    }

    // 2. Run Dijkstra N times for both graphs

    // SP_E[i][j]: Shortest path cost from i to j (Empty)
    const SP_E = [];
    for (let i = 0; i < n; i++) {
