    }

    // SP_C[i][j]: Shortest path cost from i to j (Carrying)
    const SP_C = [];
    for (let i = 0; i < n; i++) {
        SP_C.push(dijkstra(n, adjC, i));
    }

    // 3. Calculate Answer
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at shop i
        let minCost = prices[i];

        // Option 2: Travel i -> j (empty) + buy at j + travel j -> i (carrying)
