    /**
     * Runs Dijkstra's algorithm from a source node on a given adjacency list.
     * @param N Number of nodes.
     * @param adj The adjacency list representation of the graph.
     * @param startNode The starting node index.
     * @return An array of minimum distances from startNode to all other nodes.
     */
    private static long[] dijkstra(int N, List<List<Edge>> adj, int startNode) {
        long[] dist = new long[N];
        Arrays.fill(dist, Long.MAX_VALUE);

        dist[startNode] = 0;
        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(startNode, 0));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            int u = current.id;
            long d = current.distance;

            if (d > dist[u]) {
                continue;
            }

            for (Edge edge : adj.get(u)) {
                int v = edge.to;
                long weight = edge.weight;

                if (dist[u] != Long.MAX_VALUE && dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new Node(v, dist[v]));
                }
            }
        }
        return dist;
    }

    public static long[] solve(long n, long[] prices, long[][] roads) {
        int N = (int) n;

        // 1. Initialize adjacency lists for Empty travel and Carrying travel
        List<List<Edge>> adjEmpty = new ArrayList<>(N);
        List<List<Edge>> adjWith = new ArrayList<>(N);

        for (int i = 0; i < N; i++) {
            adjEmpty.add(new ArrayList<>());
            adjWith.add(new ArrayList<>());
        }

        // 2. Populate adjacency lists
        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];

            // Empty travel (Weight = cost)
            // Bidirectional
            adjEmpty.get(u).add(new Edge(v, cost));
            adjEmpty.get(v).add(new Edge(u, cost));

            // Carrying travel (Weight = cost * tax)
            // Bidirectional
            long taxedCost = cost * tax;
            adjWith.get(u).add(new Edge(v, taxedCost));
            adjWith.get(v).add(new Edge(u, taxedCost));
