        long[][] D_empty = new long[N][N];
        // D_with[i][j] = shortest path from i to j with apples
        long[][] D_with = new long[N][N];

        for (int i = 0; i < N; i++) {
            D_empty[i] = dijkstra(N, adjEmpty, i);
            D_with[i] = dijkstra(N, adjWith, i);
        }

        // 4. Calculate the final answer for each store i
        long[] ans = new long[N];

        for (int i = 0; i < N; i++) {
            // Option 1: Buy directly at i
            long minCost = prices[i];

