            for (int j = 0; j < N; j++) {
                // Cost = D_empty(i, j) + prices[j] + D_with(j, i)

                long costEmpty_i_j = D_empty[i][j];
                long costWith_j_i = D_with[j][i];

                // Check for reachability (should be handled by Long.MAX_VALUE comparison)
                if (costEmpty_i_j != Long.MAX_VALUE && costWith_j_i != Long.MAX_VALUE) {
