import java.util.*;

public class Solution {

    static class Edge {
        int to;
        long weight;

        public Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    static class State implements Comparable<State> {
        int node;
        long distance;

        public State(int node, long distance) {
            this.node = node;
            this.distance = distance;
        }

        @Override
        public int compareTo(State other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    private static final long INF = Long.MAX_VALUE / 2;

    /**
     * Runs Dijkstra's algorithm from a single start node.
     * @param n Number of nodes.
     * @param adj Adjacency list representation of the graph.
     * @param start The starting node.
     * @return An array of minimum distances from start to all other nodes.
     */
    private static long[] dijkstra(int n, List<Edge>[] adj, int start) {
        long[] dist = new long[n];
        Arrays.fill(dist, INF);
        dist[start] = 0;

        PriorityQueue<State> pq = new PriorityQueue<>();
        pq.add(new State(start, 0));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            long d = current.distance;

            if (d > dist[u]) continue;

            for (Edge edge : adj[u]) {
                int v = edge.to;
                long weight = edge.weight;

                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new State(v, dist[v]));
                }
            }
        }
        return dist;
    }

    public static long[] solve(long n_long, long[] prices, long[][] roads) {
        int n = (int) n_long;

        // 1. Build two graphs: G_empty (cost C) and G_carry (cost C * T)

        // G_empty adjacency list
        List<Edge>[] adjEmpty = new List[n];
        for (int i = 0; i < n; i++) {
            adjEmpty[i] = new ArrayList<>();
        }

        // G_carry adjacency list
        List<Edge>[] adjCarry = new List[n];
        for (int i = 0; i < n; i++) {
            adjCarry[i] = new ArrayList<>();
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];

            // Empty-handed graph (Cost = C)
            // Bidirectional
            adjEmpty[u].add(new Edge(v, cost));
            adjEmpty[v].add(new Edge(u, cost));

            // Carry graph (Cost = C * T)
            // Bidirectional
            long carryCost = cost * tax;
            adjCarry[u].add(new Edge(v, carryCost));
            adjCarry[v].add(new Edge(u, carryCost));
        }

        // 2. Calculate APSP for G_empty (D_empty[i][j] = min cost i -> j empty)
        long[][] D_empty = new long[n][n];
        for (int i = 0; i < n; i++) {
            long[] distances = dijkstra(n, adjEmpty, i);
            System.arraycopy(distances, 0, D_empty[i], 0, n);
        }

        // 3. Calculate APSP for G_carry (D_carry[j][i] = min cost j -> i carry)
        // Since roads are bidirectional, D_carry[j][i] is shortest path from j to i.
        long[][] D_carry = new long[n][n];
        for (int j = 0; j < n; j++) {
            long[] distances = dijkstra(n, adjCarry, j);
            System.arraycopy(distances, 0, D_carry[j], 0, n);
        }

        // 4. Calculate minimum cost for each store i
        long[] ans = new long[n];

        for (int i = 0; i < n; i++) {
            // Option 1: Buy directly at i
            long minCost = prices[i];

            // Option 2: Travel i -> j (empty), buy at j, travel j -> i (carry)
            for (int j = 0; j < n; j++) {
                // If i == j, the cost is prices[i], which is covered by Option 1, 
                // but the formula would yield D_empty(i, i) + prices[i] + D_carry(i, i) = 0 + prices[i] + 0.
                // We can include j=i without harm.

                long d_empty_ij = D_empty[i][j]; // Cost i -> j empty
                long d_carry_ji = D_carry[j][i]; // Cost j -> i carry

                // Check for reachability
                if (d_empty_ij != INF && d_carry_ji != INF) {
                    // Total Cost = Travel_Empty(i->j) + Price(j) + Travel_Carry(j->i)
                    long currentTotalCost = d_empty_ij + prices[j] + d_carry_ji;
                    minCost = Math.min(minCost, currentTotalCost);
                }
            }
            ans[i] = minCost;
        }

        return ans;
    }
