import java.util.*;

public class Solution {

    static class Edge {
        int to;
        long weight;

        public Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    static class State implements Comparable<State> {
        int node;
        long distance;

        public State(int node, long distance) {
            this.node = node;
            this.distance = distance;
        }

        @Override
        public int compareTo(State other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    /**
     * Dijkstra's algorithm implementation.
     * Finds shortest paths from a single source to all other nodes in a graph.
     *
     * @param n Number of nodes
     * @param adj Adjacency list representation of the graph
     * @param startNode The source node
     * @return An array of shortest distances from startNode to all other nodes.
     */
    private static long[] dijkstra(int n, List<Edge>[] adj, int startNode) {
        long[] dist = new long[n];
        long INF = Long.MAX_VALUE / 2; // Use half max to avoid overflow during addition
        Arrays.fill(dist, INF);
        dist[startNode] = 0;

        PriorityQueue<State> pq = new PriorityQueue<>();
        pq.add(new State(startNode, 0));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            long d = current.distance;

            if (d > dist[u]) {
                continue;
            }

            for (Edge edge : adj[u]) {
                int v = edge.to;
                long weight = edge.weight;

                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new State(v, dist[v]));
                }
            }
        }
        return dist;
    }

    public static long[] solve(long nLong, long[] prices, long[][] roads) {
        int n = (int) nLong;

        // 1. Initialize graphs
        // G_empty: Cost = cost_i (Empty hands)
        List<Edge>[] adjEmpty = new ArrayList[n];
        // G_full: Cost = cost_i * tax_i (Full hands)
        List<Edge>[] adjFull = new ArrayList[n];

        for (int i = 0; i < n; i++) {
            adjEmpty[i] = new ArrayList<>();
            adjFull[i] = new ArrayList<>();
        }

        // 2. Build graphs
        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];

            // Empty Graph
            adjEmpty[u].add(new Edge(v, cost));
            adjEmpty[v].add(new Edge(u, cost));

            // Full Graph
            long full_cost = cost * tax;
            adjFull[u].add(new Edge(v, full_cost));
            adjFull[v].add(new Edge(u, full_cost));
        }

        // 3. Calculate APSP for Empty Travel (D_empty[i][j] = i -> j)
        long[][] D_empty = new long[n][n];
        for (int i = 0; i < n; i++) {
            D_empty[i] = dijkstra(n, adjEmpty, i);
        }

        // 4. Calculate APSP for Full Travel (D_full[j][i] = j -> i)
        // Note: We need D_full(j, i), which is the distance from j to i using full cost.
        long[][] D_full = new long[n][n];
        for (int j = 0; j < n; j++) {
            long[] distFromJ = dijkstra(n, adjFull, j);
            // Store distFromJ[i] = D_full(j, i)
            for (int i = 0; i < n; i++) {
                D_full[j][i] = distFromJ[i];
            }
        }

        // 5. Calculate Final Answer
        long[] ans = new long[n];
        long INF = Long.MAX_VALUE / 2;

        for (int i = 0; i < n; i++) {
            // Option 1: Buy directly at i
            long minCost = prices[i];

            // Option 2: Travel to j, buy, return to i
            for (int j = 0; j < n; j++) {
                // Check if paths exist (i.e., distances are not infinity)
                long d_i_j = D_empty[i][j]; // i -> j empty
                long d_j_i = D_full[j][i];  // j -> i full

                if (d_i_j < INF && d_j_i < INF) {
                    // Total Cost = D_empty(i, j) + prices[j] + D_full(j, i)
                    long currentCost = d_i_j + prices[j] + d_j_i;
                    minCost = Math.min(minCost, currentCost);
                }
            }
            ans[i] = minCost;
        }

        return ans;
    }
}

